function findReplaceString(s, indices, sources, targets) {
    const indexMapping = indices
        .map((idx, i) => [s.startsWith(sources[i], idx) ? idx : -1, i])
        .sort((a, b) => a[0] - b[0]);
    let result = "";
    let lastIdx = 0;

    for (const [idx, i] of indexMapping) {
        if (idx >= 0) {
            result += s.slice(lastIdx, idx) + targets[i];
            lastIdx = idx + sources[i].length;
        }
    }

    result += s.slice(lastIdx);
    return result;
}
```

    1. Create an array of index mappings where an element is a pair of index and the corresponding operation index (i). Only keep the index mappings where the source is indeed a substring starting at the given index.
2. Sort the index mappings array based on the index.
3. Initialize an empty result string and a variable (lastIdx) to keep track of the last added index.
4. Iterate through the index mappings, for each index mapping, append the substring between the last added index and the current index to the result, then append the corresponding target string.
5. Update the last added index to the sum of the current index and the length of the corresponding source string.
6. After iterating through all the index mappings, append the substring from the last added index to the end of the input string to the result.
7. Return the result string.

